31	{
32	    int ret = -1;
33	
34	    if (str == NULL) {
35	        flb_error("str is NULL");
36	        return -1;
37	    }
38	
39	    switch (obj.type)  {
40	    case MSGPACK_OBJECT_STR:
41	        if (obj.via.str.size != str_len) {
42	            return -1;
43	        }
44	        ret = strncmp(str, obj.via.str.ptr, str_len);
45	        break;
46	    case MSGPACK_OBJECT_POSITIVE_INTEGER:
47	        {
48	            unsigned long val = strtoul(str, NULL, 10);
