54	    case MSGPACK_OBJECT_NEGATIVE_INTEGER:
55	        {
56	            long long val = strtoll(str, NULL, 10);
57	            if (val == (unsigned long)obj.via.i64) {
58	                ret = 0;
59	            }
60	        }
61	        break;
62	    case MSGPACK_OBJECT_FLOAT32:
63	    case MSGPACK_OBJECT_FLOAT64:
64	        {
65	            double val = strtod(str, NULL);
66	            if (fabs(val - obj.via.f64) < DBL_EPSILON) {
67	                ret = 0;
68	            }
69	        }
70	        break;
71	    case MSGPACK_OBJECT_BOOLEAN:
72	        if (obj.via.boolean) {
73	            if (str_len != 4 /*true*/) {
74	                return -1;
75	            }
