97	static int compare_msgpack(void *msgpack_data, size_t msgpack_size, struct str_list *l)
98	{
99	    msgpack_unpacked result;
100	    msgpack_object obj;
101	    size_t off = 0;
102	    int map_size;
103	    int i_map;
104	    int i_list;
105	    int num = 0;
106	
107	    if (!TEST_CHECK(msgpack_data != NULL)) {
108	        TEST_MSG("msgpack_data is NULL");
109	        return -1;
110	    }
111	    else if (!TEST_CHECK(msgpack_size > 0)) {
112	        TEST_MSG("msgpack_size is 0");
113	        return -1;
114	    }
115	
116	    msgpack_unpacked_init(&result);
117	    while (msgpack_unpack_next(&result, msgpack_data, msgpack_size, &off) == MSGPACK_UNPACK_SUCCESS) {
118	        obj = result.data;
119	        /*
120	        msgpack_object_print(stdout, obj);
121	        */
122	        if (!TEST_CHECK(obj.type == MSGPACK_OBJECT_MAP)) {
123	            TEST_MSG("map error. type = %d", obj.type);
124	            continue;
125	        }
126	        map_size = obj.via.map.size;
127	        for (i_map=0; i_map<map_size; i_map++) {
128	            if (!TEST_CHECK(obj.via.map.ptr[i_map].key.type == MSGPACK_OBJECT_STR)) {
129	                TEST_MSG("key is not string. type =%d", obj.via.map.ptr[i_map].key.type);
130	                continue;
131	            }
132	            for (i_list=0; i_list< l->size/2; i_list++)  {
133	                if (msgpack_strncmp(l->lists[i_list*2], strlen(l->lists[i_list*2]),
134	                                    obj.via.map.ptr[i_map].key) == 0 &&
135	                    msgpack_strncmp(l->lists[i_list*2+1], strlen(l->lists[i_list*2+1]),
136	                                    obj.via.map.ptr[i_map].val) == 0) {
137	                    num++;
138	                }
139	            }
140	        }
141	    }
142	    msgpack_unpacked_destroy(&result);
143	    if (!TEST_CHECK(num == l->size/2)) {
144	        msgpack_object_print(stdout, obj);
145	        putchar('\n');
146	        TEST_MSG("compare failed. matched_num=%d expect=%lu", num, l->size/2);
147	        return -1;
148	    }
149	    return 0;
150	}
