159	    void *out_buf = NULL;
160	    size_t out_size = 0;
161	    struct flb_time out_time;
162	    char *expected_strs[] = {"str", "text", "int", "100", "double","1.23", "bool", "true"};
163	    struct str_list expected = {
164	                                .size = sizeof(expected_strs)/sizeof(char*),
165	                                .lists = &expected_strs[0],
166	    };
167	
168	    config = flb_config_init();
