170	        TEST_MSG("flb_config_init failed");
171	        exit(1);
172	    }
173	
174	    parser = flb_parser_create("regex", "regex", regex, FLB_FALSE, NULL, NULL, NULL,
175	                               FLB_FALSE, FLB_FALSE, FLB_FALSE, FLB_FALSE,
176	                               NULL, 0, NULL, config);
177	    if (!TEST_CHECK(parser != NULL)) {
178	        TEST_MSG("flb_parser_create failed");
179	        flb_config_exit(config);
180	        exit(1);
181	    }
182	
183	    ret = flb_parser_do(parser, input, strlen(input), &out_buf, &out_size, &out_time);
184	    if (!TEST_CHECK(ret != -1)) {
185	        TEST_MSG("flb_parser_do failed");
186	        flb_parser_destroy(parser);
187	        flb_config_exit(config);
188	        exit(1);
