190	
191	    ret = compare_msgpack(out_buf, out_size, &expected);
192	    if (!TEST_CHECK(ret == 0)) {
193	        TEST_MSG("compare failed");
194	    }
195	
196	    flb_free(out_buf);
197	    flb_parser_destroy(parser);
198	    flb_config_exit(config);
199	}
