				break;
			}
			/* PM? */
			len = strlen(_ctloc(PM_STR));
			if (strncasecmp(_ctloc(PM_STR), (const char *)bp, len) == 0) {
				if (tm->tm.tm_hour > 12)	/* i.e., 13:00 PM ?! */
					return (NULL);
				else if (tm->tm.tm_hour < 12)
